const item = $input.first().json;
const raw = item.stdout || item.output || '';
const exitCode = item.exitCode ?? item.code ?? null;

function pick(label) {
  const re = new RegExp('^' + label + ':\\s*(.+)$', 'mi');
  const m = raw.match(re);
  return m ? m[1].trim() : 'unknown';
}

const promptReady = pick('Prompt ready');
const embeddedFormat = pick('Embedded format');
const taskStatus = pick('Task status');
const operationType = pick('Operation type');
const riskLevel = pick('Risk level');

const text = [
  'CONTROL PLANE handoff',
  'Prompt ready: ' + promptReady,
  'Embedded format: ' + embeddedFormat,
  'Task status: ' + taskStatus,
  'Operation type: ' + operationType,
  'Risk level: ' + riskLevel,
  'Exit code: ' + (exitCode ?? 'unknown'),
  'Target: cursor-coordinate-converter',
  'Mode: manual dry-run',
].join('\n');

return [{ json: { stdout: raw, exitCode, promptReady, embeddedFormat, taskStatus, operationType, riskLevel, text } }];
